<?phprequire __DIR__ . '/../config.php';$filename = '';$file = new \Nemundo\Core\File\File($filename);(new \Nemundo\Core\Debug\Debug())->write($file->getFilename());(new \Nemundo\Core\Debug\Debug())->write($file->getFileExtension());(new \Nemundo\Core\Debug\Debug())->write($file->getFileSize());if ($file->fileExists()) {    (new \Nemundo\Core\Debug\Debug())->write('File exists');} else {    (new \Nemundo\Core\Debug\Debug())->write('File does not exist');}